import React, { useState, useCallback } from 'react';
import PersonaSelector from './components/PersonaSelector';
import WashingMachine from './components/WashingMachine';
import ResultDisplay from './components/ResultDisplay';
import { PersonaId } from './types';
import { generateCounseling } from './services/geminiService';

const App: React.FC = () => {
  const [selectedPersonaId, setSelectedPersonaId] = useState<PersonaId | null>(null);
  const [worryText, setWorryText] = useState('');
  const [isWashing, setIsWashing] = useState(false);
  const [result, setResult] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleWash = async () => {
    if (!selectedPersonaId || !worryText.trim()) return;

    setIsWashing(true);
    setError(null);
    setResult(null);

    try {
      const response = await generateCounseling(worryText, selectedPersonaId);
      setResult(response || "결과를 생성할 수 없습니다.");
    } catch (err) {
      setError("상담 도중 오류가 발생했습니다. 다시 시도해주세요.");
      console.error(err);
    } finally {
      setIsWashing(false);
    }
  };

  const reset = () => {
    setResult(null);
    setWorryText('');
    setSelectedPersonaId(null);
    setError(null);
  };

  return (
    <div className="min-h-screen bg-gradient-to-b from-blue-50 to-white pb-20">
      {/* Header */}
      <header className="bg-white border-b border-blue-100 sticky top-0 z-50">
        <div className="max-w-5xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-10 h-10 bg-blue-600 rounded-lg flex items-center justify-center text-white shadow-lg">
              <i className="fas fa-soap"></i>
            </div>
            <div>
              <h1 className="text-xl font-bold text-slate-800">고민 세탁기</h1>
              <p className="text-[10px] text-blue-500 font-medium tracking-widest uppercase">Worry Washer AI</p>
            </div>
          </div>
          <div className="text-sm text-slate-500 hidden md:block">
            사내 업무 고민 해결 플랫폼
          </div>
        </div>
      </header>

      <main className="max-w-5xl mx-auto px-4 mt-8">
        {!result && !isWashing && (
          <div className="max-w-3xl mx-auto animate-fade-in">
            <div className="text-center mb-10">
              <h2 className="text-3xl font-bold text-slate-800 mb-2">어떤 고민을 세탁해 드릴까요?</h2>
              <p className="text-slate-500">상담사를 선택하고 당신의 고민을 입력해 주세요.</p>
            </div>

            <section className="mb-10">
              <h3 className="text-lg font-bold text-slate-700 mb-4 flex items-center gap-2">
                <span className="bg-blue-600 text-white w-6 h-6 rounded-full flex items-center justify-center text-xs">1</span>
                상담사 선택
              </h3>
              <PersonaSelector 
                selectedId={selectedPersonaId} 
                onSelect={setSelectedPersonaId} 
              />
            </section>

            <section className="mb-10">
              <h3 className="text-lg font-bold text-slate-700 mb-4 flex items-center gap-2">
                <span className="bg-blue-600 text-white w-6 h-6 rounded-full flex items-center justify-center text-xs">2</span>
                고민 입력
              </h3>
              <div className="relative">
                <textarea
                  value={worryText}
                  onChange={(e) => setWorryText(e.target.value)}
                  placeholder="예: 과도한 업무량 때문에 번아웃이 올 것 같아요. / 상사와의 소통이 너무 힘들어서 퇴사하고 싶습니다."
                  className="w-full h-48 p-6 rounded-2xl border-2 border-slate-200 focus:border-blue-500 focus:ring-4 focus:ring-blue-100 outline-none transition-all resize-none shadow-sm text-slate-700"
                ></textarea>
                <div className="absolute bottom-4 right-4 text-xs text-slate-400">
                  {worryText.length} / 1000
                </div>
              </div>
            </section>

            <div className="flex justify-center">
              <button
                onClick={handleWash}
                disabled={!selectedPersonaId || !worryText.trim()}
                className={`group px-10 py-4 rounded-full font-bold text-lg flex items-center gap-3 transition-all ${
                  selectedPersonaId && worryText.trim()
                    ? 'bg-blue-600 text-white shadow-xl hover:bg-blue-700 hover:-translate-y-1'
                    : 'bg-slate-200 text-slate-400 cursor-not-allowed'
                }`}
              >
                <i className={`fas fa-sync-alt ${selectedPersonaId && worryText.trim() ? 'group-hover:rotate-180 transition-transform duration-500' : ''}`}></i>
                세탁 시작하기
              </button>
            </div>

            {error && (
              <p className="text-red-500 text-center mt-4 font-medium">{error}</p>
            )}
          </div>
        )}

        {isWashing && <WashingMachine />}

        {result && selectedPersonaId && (
          <ResultDisplay 
            content={result} 
            personaId={selectedPersonaId} 
            onReset={reset}
          />
        )}
      </main>

      {/* Footer Info */}
      {!isWashing && !result && (
        <footer className="mt-20 max-w-2xl mx-auto px-4">
          <div className="bg-white/50 border border-slate-200 rounded-2xl p-6 text-sm text-slate-500">
            <h4 className="font-bold text-slate-700 mb-2 flex items-center gap-2">
              <i className="fas fa-info-circle text-blue-500"></i> 이용 안내
            </h4>
            <ul className="space-y-1 list-disc list-inside">
              <li>고민 세탁기는 직장 내 스트레스와 고민을 긍정적으로 해소하기 위해 만들어졌습니다.</li>
              <li>입력하신 내용은 AI 분석을 위한 용도로만 사용됩니다.</li>
              <li>심각한 심리적 위기 상황이라면 전문 심리 상담실 방문을 권장합니다.</li>
            </ul>
          </div>
        </footer>
      )}
    </div>
  );
};

export default App;

