import React, { useState, useRef, useEffect } from 'react';
import { PersonaId, ChatMessage } from '../types';
import { PERSONAS } from '../constants';

interface ResultDisplayProps {
  messages: ChatMessage[];
  personaId: PersonaId;
  onReset: () => void;
  onSendMessage: (message: string) => void;
  isSending: boolean;
}

const ResultDisplay: React.FC<ResultDisplayProps> = ({ 
  messages, 
  personaId, 
  onReset, 
  onSendMessage,
  isSending 
}) => {
  const persona = PERSONAS.find(p => p.id === personaId);
  const [inputText, setInputText] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputText.trim() || isSending) return;
    onSendMessage(inputText);
    setInputText('');
  };

  const renderMessageContent = (msg: ChatMessage) => {
    if (msg.role === 'user') return msg.text;

    // Split initial laundry report if it's the first message
    if (msg.text.includes('---')) {
      const sections = msg.text.split('---');
      const chatPart = sections[0] || '';
      const solutionPart = sections[1] || '';

      return (
        <div className="space-y-4">
          <div className="italic mb-4 whitespace-pre-wrap">{chatPart.replace('[캐릭터 대화]:', '').trim()}</div>
          <div className="bg-white/50 p-4 rounded-xl border border-blue-100 shadow-sm">
            <h5 className="font-bold text-blue-600 mb-2 text-sm flex items-center gap-2">
              <i className="fas fa-magic"></i> 세탁 완료 솔루션
            </h5>
            <div className="text-sm whitespace-pre-wrap leading-relaxed">
              {solutionPart.replace('[세탁 완료: 업무 지속을 위한 3단계 솔루션]:', '').trim()}
            </div>
          </div>
        </div>
      );
    }

    return <div className="whitespace-pre-wrap leading-relaxed">{msg.text}</div>;
  };

  return (
    <div className="max-w-4xl mx-auto flex flex-col h-[75vh] bg-white rounded-3xl shadow-2xl overflow-hidden border border-slate-200">
      {/* Header */}
      <div className={`${persona?.color || 'bg-blue-600'} p-4 text-white flex items-center justify-between shrink-0`}>
