import React, { useState } from 'react';
import PersonaSelector from './components/PersonaSelector';
import WashingMachine from './components/WashingMachine';
import ResultDisplay from './components/ResultDisplay';
import { PersonaId, ChatMessage } from './types';
import { createChatSession } from './services/geminiService';
import { Chat, GenerateContentResponse } from '@google/genai';

const App: React.FC = () => {
  const [selectedPersonaId, setSelectedPersonaId] = useState<PersonaId | null>(null);
  const [worryText, setWorryText] = useState('');
  const [isWashing, setIsWashing] = useState(false);
  const [isSending, setIsSending] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [activeChat, setActiveChat] = useState<Chat | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleInitialWash = async () => {
    if (!selectedPersonaId || !worryText.trim()) return;

    setIsWashing(true);
    setError(null);
    setMessages([]);

    try {
      const chat = createChatSession(selectedPersonaId);
      setActiveChat(chat);

      // Initial user message added locally
      const userMsg: ChatMessage = { role: 'user', text: worryText, timestamp: Date.now() };

      // Get initial response
      const response = await chat.sendMessage({ message: worryText });
      const modelText = response.text || "";

      setMessages([
        userMsg,
        { role: 'model', text: modelText, timestamp: Date.now() }
      ]);
    } catch (err) {
      setError("상담을 시작하는 도중 오류가 발생했습니다. 다시 시도해주세요.");
      console.error(err);
    } finally {
      setIsWashing(false);
    }
  };

  const handleSendMessage = async (text: string) => {
    if (!activeChat || !text.trim() || isSending) return;

    setIsSending(true);
    const userMsg: ChatMessage = { role: 'user', text, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);

    try {
      // Use streaming for better experience
      const responseStream = await activeChat.sendMessageStream({ message: text });

      let fullText = "";
      // Create an initial empty model message
      setMessages(prev => [...prev, { role: 'model', text: "", timestamp: Date.now() }]);

      for await (const chunk of responseStream) {
        const chunkText = (chunk as GenerateContentResponse).text;
        if (chunkText) {
          fullText += chunkText;
          setMessages(prev => {
            const last = prev[prev.length - 1];
            if (last.role === 'model') {
              const updated = [...prev];
              updated[updated.length - 1] = { ...last, text: fullText };
              return updated;
            }
            return prev;
          });
        }
      }
    } catch (err) {
      setError("메시지 전송 중 오류가 발생했습니다.");
      console.error(err);
    } finally {
      setIsSending(false);
    }
  };

  const reset = () => {
    setMessages([]);
    setActiveChat(null);
    setWorryText('');
    setSelectedPersonaId(null);
    setError(null);
  };

